inline void Snapshot::WriteTo(nanobuf::Writer& w) const {
  w.Begin(kFixedLen);
  w.PutScalar(8, this->server_tick);
  w.PutBit(2, 0, this->full);
  w.PutOffsetList(4, this->entities, [](nanobuf::Writer& inner, const EntityState& item) {
    return inner.HeapMessage([&item](nanobuf::Writer& nested) {
      item.WriteTo(nested);
    });
  });
  w.PutScalarList(16, this->despawned);
}

inline std::vector<uint8_t> Snapshot::EncodeProto3() const {
  std::vector<uint8_t> out;
  WriteProto3To(out);
  return out;
}

inline void Snapshot::WriteProto3To(std::vector<uint8_t>& out) const {
  if (this->server_tick != 0) {
    nanobuf::proto::WriteVarintField(out, 1, static_cast<uint64_t>(this->server_tick));
  }
  if (this->full) {
    nanobuf::proto::WriteVarintField(out, 2, static_cast<uint64_t>(this->full));
  }
  if (!this->entities.empty()) {
    for (size_t i = 0; i < this->entities.size(); ++i) {
      nanobuf::proto::WriteLenFieldWith(out, 3, [&](std::vector<uint8_t>& nested) {
        this->entities[i].WriteProto3To(nested);
      });
    }
  }
  if (!this->despawned.empty()) {
    nanobuf::proto::WriteLenFieldWith(out, 4, [&](std::vector<uint8_t>& payload) {
      for (size_t i = 0; i < this->despawned.size(); ++i) {
        nanobuf::proto::WriteVarint(payload, static_cast<uint64_t>(this->despawned[i]));
      }
    });
  }
}

inline std::optional<Snapshot> Snapshot::DecodeProto3(const uint8_t* data, size_t size) {
  Snapshot message;
  nanobuf::proto::FieldReader reader(data, size);
  uint32_t field = 0;
  nanobuf::proto::WireValue value;
  while (true) {
    nanobuf::proto::FieldReader::Status status = reader.Next(&field, &value);
    if (status == nanobuf::proto::FieldReader::Status::kDone) {
      break;
    }
    if (status == nanobuf::proto::FieldReader::Status::kError) {
      return std::nullopt;
    }
    switch (field) {
      case 1: {
        uint64_t raw;
        if (!nanobuf::proto::ExpectVarint(value, &raw)) {
          return std::nullopt;
        }
        message.server_tick = static_cast<uint64_t>(raw);
        break;
      }
      case 2: {
        uint64_t raw;
        if (!nanobuf::proto::ExpectVarint(value, &raw)) {
          return std::nullopt;
        }
        message.full = raw != 0;
        break;
      }
      case 3: {
        const uint8_t* payload;
        size_t payload_size;
        if (!nanobuf::proto::ExpectLen(value, &payload, &payload_size)) {
          return std::nullopt;
        }
        std::optional<EntityState> child = EntityState::DecodeProto3(payload, payload_size);
        if (!child.has_value()) {
          return std::nullopt;
        }
        message.entities.push_back(std::move(*child));
        break;
      }
      case 4: {
        bool ok = nanobuf::proto::ReadPackedVarints(value, [&message](uint64_t v) {
          message.despawned.push_back(static_cast<uint64_t>(v));
        });
        if (!ok) {
          return std::nullopt;
        }
        break;
      }
      default:
        break;  // unknown field, skipped
    }
  }
  return message;
}

inline std::optional<SnapshotView> SnapshotView::Parse(const uint8_t* data, size_t size) {
  std::optional<nanobuf::View> view = nanobuf::View::Parse(data, size);
  if (!view.has_value()) {
    return std::nullopt;
  }
  return SnapshotView(*view);
}

inline uint64_t SnapshotView::server_tick() const {
  return view_.ScalarAt<uint64_t>(8);
}

inline bool SnapshotView::full() const {
  return view_.BitAt(2, 0);
}

inline std::optional<nanobuf::MessageList<EntityStateView>> SnapshotView::entities() const {
  std::optional<nanobuf::OffsetList> list = view_.OffsetListAt(4);
  if (!list.has_value()) {
    return std::nullopt;
  }
  return nanobuf::MessageList<EntityStateView>(*list);
}

inline std::optional<nanobuf::ScalarList<uint64_t>> SnapshotView::despawned() const {
  return view_.ScalarListAt<uint64_t>(16);
}

inline std::optional<Snapshot> SnapshotView::ToOwned() const {
  Snapshot out;
  out.server_tick = this->server_tick();
  out.full = this->full();
  {
    auto value = this->entities();
    if (!value.has_value()) {
      return std::nullopt;
    }
    for (size_t i = 0; i < value->size(); ++i) {
      std::optional<EntityStateView> item = value->Get(i);
      if (!item.has_value()) {
        return std::nullopt;
      }
      std::optional<EntityState> child = item->ToOwned();
      if (!child.has_value()) {
        return std::nullopt;
      }
      out.entities.push_back(std::move(*child));
    }
  }
  {
    auto value = this->despawned();
    if (!value.has_value()) {
      return std::nullopt;
    }
    out.despawned = value->ToVector();
  }
  return out;
}

